import { createClient } from '@/lib/supabase/server';
import AddPodcastForm from '@/components/admin/AddPodcastForm';
import DeletePodcastButton from '@/components/admin/DeletePodcastButton';
import { Podcast as PodcastType } from '@/types';
import { Pencil, Filter, Mic2, Globe, Music, FileText, Link as LinkIcon, Sparkles } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { SearchInput } from '@/components/ui/SearchInput';
import { getAdminPermissions } from '@/lib/supabase/permissions';

export const metadata = {
  title: 'Podcasts | Admin Portal',
};

interface PageProps {
  searchParams: Promise<{ q?: string }>;
}

export default async function AdminPodcastsPage({ searchParams }: PageProps) {
  const { q } = await searchParams;
  const supabase = await createClient();
  
  const { data: { user } } = await supabase.auth.getUser();
  const permissions = user ? await getAdminPermissions(user.id) : null;

  let query = supabase
    .from('podcasts')
    .select('*')
    .order('created_at', { ascending: false });

  if (q) {
    query = query.or(`title.ilike.%${q}%,language.ilike.%${q}%`);
  }

  const { data: podcasts, error } = await query;

  if (error) {
    console.error('Error fetching podcasts for admin:', error);
  }

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-2 h-8 bg-saffron rounded-full shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
            <h1 className="text-5xl font-bold font-heading text-white tracking-tight">
              Podcasts
            </h1>
          </div>
          <p className="text-white/50 font-medium italic pl-5">Listen to the spoken wisdom of the ages.</p>
        </div>
        <div className="flex items-center gap-4">
          <Button variant="outline" size="sm" leftIcon={<Filter size={16} />} className="border-white/10 text-white/70 hover:text-white hover:bg-white/10 backdrop-blur-xl rounded-2xl transition-all duration-500 h-12 px-6">
            Refine View
          </Button>
          {permissions?.can_write && <AddPodcastForm />}
        </div>
      </div>

      {/* Search Bar */}
      <SearchInput placeholder="Search the audio archive..." />

      <div className="glass-card overflow-hidden border border-white/5 shadow-2xl rounded-[2.5rem] bg-white/[0.02] backdrop-blur-3xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/[0.03] border-b border-white/10 text-white/30 text-[10px] font-black uppercase tracking-[0.3em]">
                <th className="px-10 py-7">Podcast Details</th>
                <th className="px-10 py-7">Language</th>
                <th className="px-10 py-7">Resources</th>
                <th className="px-10 py-7">Status</th>
                <th className="px-10 py-7 text-right">Management</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {podcasts && podcasts.length > 0 ? (
                podcasts.map((podcast: PodcastType) => (
                  <tr key={podcast.id} className="hover:bg-white/[0.04] transition-all duration-500 group">
                    <td className="px-10 py-8">
                      <div className="flex flex-col gap-2">
                        <div className="font-bold text-white group-hover:text-saffron transition-colors text-xl tracking-tight italic">
                          {podcast.title}
                        </div>
                        {podcast.book_id && (
                          <div className="flex items-center gap-2 text-[10px] text-white/20 font-black tracking-widest uppercase">
                            <LinkIcon size={10} className="text-saffron/40" />
                            Book ID: {podcast.book_id}
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-10 py-8">
                      <div className="flex items-center gap-3 text-sm text-white/60 font-medium italic">
                        <Globe size={16} className="text-saffron/60" />
                        {podcast.language}
                      </div>
                    </td>
                    <td className="px-10 py-8">
                      <div className="flex items-center gap-4">
                        <div className={`p-3 rounded-xl border ${podcast.audio_url ? 'bg-emerald-500/5 text-emerald-400 border-emerald-500/20 shadow-[0_0_15px_rgba(52,211,153,0.1)]' : 'bg-white/5 text-white/10 border-white/5'}`} title={podcast.audio_url ? 'Audio link available' : 'No audio link'}>
                          <Music size={18} />
                        </div>
                        <div className={`p-3 rounded-xl border ${podcast.transcript ? 'bg-saffron/5 text-saffron border-saffron/20 shadow-[0_0_15px_rgba(245,158,11,0.1)]' : 'bg-white/5 text-white/10 border-white/5'}`} title={podcast.transcript ? 'Transcript available' : 'No transcript'}>
                          <FileText size={18} />
                        </div>
                      </div>
                    </td>
                    <td className="px-10 py-8">
                      <span className={`inline-flex items-center gap-3 text-[10px] font-black uppercase tracking-[0.2em] ${
                        podcast.status === 'published' ? 'text-emerald-400' : 'text-saffron'
                      }`}>
                        <span className={`w-2 h-2 rounded-full ${
                          podcast.status === 'published' ? 'bg-emerald-400 shadow-[0_0_12px_rgba(52,211,153,0.6)] animate-pulse' : 'bg-saffron shadow-[0_0_12px_rgba(245,158,11,0.6)]'
                        }`} />
                        {podcast.status}
                      </span>
                    </td>
                    <td className="px-10 py-8 text-right">
                      <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all duration-500 translate-x-4 group-hover:translate-x-0">
                        {permissions?.can_edit && (
                          <Button variant="ghost" size="icon" className="h-11 w-11 text-white/20 hover:text-white hover:bg-white/10 rounded-2xl transition-all shadow-xl border border-transparent hover:border-white/5">
                            <Pencil size={20} />
                          </Button>
                        )}
                        {permissions?.can_delete && <DeletePodcastButton id={podcast.id} />}
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-10 py-40 text-center">
                    <div className="flex flex-col items-center max-w-sm mx-auto">
                      <div className="relative group/empty mb-10">
                        <div className="absolute inset-0 bg-saffron/20 blur-3xl rounded-full opacity-50 group-hover/empty:opacity-100 transition-opacity duration-1000" />
                        <div className="relative w-28 h-28 bg-white/[0.03] rounded-[2.5rem] flex items-center justify-center border border-white/10 backdrop-blur-3xl shadow-inner overflow-hidden">
                          <Mic2 size={44} className="text-white/10 group-hover/empty:text-saffron transition-all duration-700 group-hover/empty:scale-110" />
                          <div className="absolute inset-0 bg-gradient-to-tr from-saffron/10 to-transparent opacity-0 group-hover/empty:opacity-100 transition-opacity" />
                        </div>
                      </div>
                      <h3 className="font-bold text-white text-3xl mb-4 tracking-tight">
                        {q ? 'No matching podcasts' : 'Studio is silent'}
                      </h3>
                      <p className="text-white/40 mb-12 text-base font-medium italic leading-relaxed font-serif">
                        {q 
                          ? `We couldn't find any podcasts matching "${q}". Please try an alternative path.` 
                          : 'Your collection of audio wisdom is waiting to be recorded. Start by adding your first podcast.'}
                      </p>
                      {permissions?.can_write && !q && (
                        <div className="flex justify-center scale-110">
                          <AddPodcastForm />
                        </div>
                      )}
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Footer Insight */}
      <div className="flex items-center justify-center py-6 text-[10px] font-black uppercase tracking-[0.4em] text-white/10">
        <Sparkles size={14} className="mr-4" />
        Vibrations of Eternal Truth
      </div>
    </div>
  );
}
